export function NavTaglineOrnamentIcon({ side = 'left' }) {
  const pathData = side === 'right' ? NAV_TAGLINE_RIGHT_PATH : NAV_TAGLINE_LEFT_PATH
  const sideClass = side === 'right' ? ' navbar-tagline-ornament-right' : ' navbar-tagline-ornament-left'
  return (
    <svg
      className={`navbar-tagline-ornament${sideClass}`}
      viewBox="0 0 273 141"
      aria-hidden="true"
      focusable="false"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path d={pathData} stroke="none" fill="currentColor" fillRule="evenodd" />
    </svg>
  )
}

